// ======================================================================
    // TODO(agent): implement the fused two-shot all-reduce + RMSNorm epilogue.
    //
    // This kernel must, in ONE pass and without an extra HBM round-trip of the
    // all-reduced intermediate:
    //   1. perform the two-shot quick all-reduce of `input` across ranks into a
    //      register/shared-memory accumulator (see AllReduceTwoshot::run for the
    //      all-reduce-only version of this exact communication pattern), then
    //   2. add the per-rank `residual_inp` to the reduced value, writing the sum
    //      to `residual_out` (the pre-normalization residual stream), then
    //   3. compute RMSNorm over the `hidden_dim` axis on that sum:
    //         denom = rsqrt( mean(x^2 over hidden_dim) + eps )
    //         output = x * denom * weight
    //      writing the normalized result to `output`.
    //
    // `N` = total elements, `hidden_dim` = normalization width, one row per token.
    // `weight` has `hidden_dim` elements. `T`/`CommT` are fp16 or bf16.
    //
    // The current stub only zero-fills the outputs, so it compiles and runs but
    // does NOT match the reference — the accuracy test will fail until the fused
    // epilogue is implemented here.
    // ======================================================================
    __device__ static void run(T const* __restrict__ input,
                               T const* __restrict__ residual_inp,
                               T* __restrict__ residual_out,
                               T* __restrict__ output,
                               T const* __restrict__ weight,
                               float eps,
                               uint32_t const N,
                               uint32_t const hidden_dim,
                               int const block,
                               int const rank,
                               uint8_t** __restrict__ buffer_list,
                               uint32_t const data_offset,
                               uint32_t flag_color,
                               int64_t data_size_per_phase)
    {
        // Stub: zero the outputs for this block's tile so the kernel is a no-op
        // placeholder. Replace with the real fused all-reduce + RMSNorm.
        int thread = threadIdx.x + threadIdx.y * kWavefront;
        int grid   = gridDim.x;
        for(uint32_t idx = (uint32_t)(block) * blockDim.x * blockDim.y + thread;
            idx < N;
            idx += (uint32_t)grid * blockDim.x * blockDim.y)
        {
            output[idx]       = qr_from_float<T>(0.0f);
            residual_out[idx] = qr_from_float<T>(0.0f);
        }
    }

arguments.newString:
// Each thread's contiguous chunk within a tile (in elements).
    static constexpr int kElemsPerThread = kAtoms * (sizeof(int32x4_t) / sizeof(T));
    static_assert(kElemsPerThread == 32);

    // Number of rows that fit in one tile.
    static constexpr int kRowsPerTile =
        (kTileSize) / (hidden_dim * sizeof(T));

    // Number of elements per row per thread (rounded up so all threads
    // covering the tile's row-span participate in the row-local reduction).
    //
    // Within one tile, if kRowsPerTile rows are packed, each row occupies
    // (tile_elems / kRowsPerTile) elements, and this many per thread:
    static constexpr int kRowElemsPerTile  = kTileSize / (kRowsPerTile * sizeof(T));
    static constexpr int kRowAtomsPerThread = kRowElemsPerTile / kElemsPerThread;

    __device__ static void run(T const* __restrict__ input,
                               T const* __restrict__ residual_inp,
                               T* __restrict__ residual_out,
                               T* __restrict__ output,
                               T const* __restrict__ weight,
                               float eps,
                               uint32_t const N,
                               uint32_t const hidden_dim,
                               int const block,
                               int const rank,
                               uint8_t** __restrict__ buffer_list,
                               uint32_t const data_offset,
                               uint32_t flag_color,
                               int64_t data_size_per_phase)
    {
        // Topology
        int thread           = threadIdx.x + threadIdx.y * kWavefront;
        uint8_t* rank_buffer = buffer_list[rank];
        Codec codec(thread, rank);
        int block_id = blockIdx.x;
        uint8_t* buffer_ptr[kWorldSize];
        for(int i = 0; i < kWorldSize; ++i)
        {
            buffer_ptr[i] = buffer_list[i];
        }

        // --------------------------------------------------------
        // Read input into registers
        int32x4_t tA[kAtoms];

        BufferResource src_buffer(const_cast<T*>(input), N * sizeof(T));
        uint32_t src_offset = block * kTileSize + thread * sizeof(int32x4_t);

        for(int i = 0; i < kAtoms; i++)
        {
            tA[i] = buffer_load_dwordx4(src_buffer.descriptor, src_offset, 0, 0);
            src_offset += kAtomStride * sizeof(int32x4_t);
            if constexpr(cast_bf2half)
            {
                const nv_bfloat162* bf_buf = reinterpret_cast<const nv_bfloat162*>(&tA[i]);
                half2 half_buf[4];
#pragma unroll
                for(int j = 0; j < 4; ++j)
                {
                    float2 f    = __bfloat1622float2(bf_buf[j]);
                    half_buf[j] = __float22half2_rn(f);
                }
                tA[i] = *reinterpret_cast<const int32x4_t*>(half_buf);
            }
        }

        // --------------------------------------------------------
        // Phase-1A: Write segment data into the communication buffer of the target
        // rank responsible for this segment.
        uint32_t comm_data0_offset = data_offset + block_id * Codec::kTransmittedTileSize;
        uint32_t comm_data1_offset = data_size_per_phase + comm_data0_offset;

        uint32_t comm_flags0_offset = block_id * (kWorldSize * sizeof(uint32_t));
        uint32_t comm_flags1_offset = (data_offset / 2) + comm_flags0_offset;

        for(int r = 0; r < kWorldSize; r++)
        {
            int32x4_t* send_buffer = reinterpret_cast<int32x4_t*>(
                buffer_ptr[r] + comm_data0_offset + rank * Codec::kRankTransmittedTileSize);
            codec.send(send_buffer, &tA[r * Codec::kRankAtoms]);
        }

        __syncthreads();
        if(thread < kWorldSize)
        {
            int r              = thread;
            uint32_t* flag_ptr = reinterpret_cast<uint32_t*>(buffer_ptr[r] + comm_flags0_offset +
                                                              rank * sizeof(uint32_t));
            set_sync_flag(flag_ptr, flag_color);
        }

        // --------------------------------------------------------
        // Phase-1B: Reduce the segment data from the communication buffers.
        int32x4_t tR[Codec::kRankAtoms] = {};
        {
            int32x4_t* recv_buffer = reinterpret_cast<int32x4_t*>(rank_buffer + comm_data0_offset);
            uint32_t* flag_ptr     = reinterpret_cast<uint32_t*>(rank_buffer + comm_flags0_offset);

            for(int r = 0; r < kWorldSize; r++)
            {
                if(thread == 0)
                {
                    wait_sync_flag(&flag_ptr[r], flag_color);
                }
                __syncthreads();

                codec.recv(&recv_buffer, tA);

                for(int i = 0; i < Codec::kRankAtoms; i++)
                {
                    packed_assign_add<T>(&tR[i], &tA[i]);
                }
            }
        }

        // --------------------------------------------------------
        // Phase-2: Write the reduced segment to every other rank
        for(int r = 0; r < kWorldSize; r++)
        {
            int32x4_t* send_buffer = reinterpret_cast<int32x4_t*>(
                buffer_ptr[r] + comm_data1_offset + rank * Codec::kRankTransmittedTileSize);
            codec.send(send_buffer, tR);
        }

        __syncthreads();
        if(thread < kWorldSize)
        {
            int r              = thread;
            uint32_t* flag_ptr = reinterpret_cast<uint32_t*>(buffer_ptr[r] + comm_flags1_offset +
                                                              rank * sizeof(uint32_t));
            set_sync_flag(flag_ptr, flag_color);
        }

        // --------------------------------------------------------
        // Phase-2: Read the gather segments from the rank's communication buffer.
        {
            int32x4_t* recv_buffer = reinterpret_cast<int32x4_t*>(rank_buffer + comm_data1_offset);
            uint32_t* flag_ptr     = reinterpret_cast<uint32_t*>(rank_buffer + comm_flags1_offset);

            for(int r = 0; r < kWorldSize; r++)
            {
                if(thread == 0)
                {
                    wait_sync_flag(&flag_ptr[r], flag_color);
                }
                __syncthreads();

                codec.recv(&recv_buffer, &tA[r * Codec::kRankAtoms]);
            }
        }

        // --------------------------------------------------------
        // At this point tA[0..kAtoms-1] holds the all-reduced result.
        // Now fuse the add-residual + RMSNorm epilogue.
        // --------------------------------------------------------

        // The tile covers kTileSize bytes. Each thread owns kElemsPerThread
        // contiguous elements (offset by thread * sizeof(int32x4_t) within the
        // tile). The rows are packed row-major.
        //
        // For each row in this tile, compute the per-thread sum-of-squares
        // contribution, reduce across the threads covering that row via
        // shared memory / warp shuffle, then apply the norm.

        constexpr int kTileElems = kTileSize / sizeof(T);

        // Number of complete rows in this tile.
        int const tile_row_start = (block * kTileSize / sizeof(T)) / hidden_dim;
        int const num_rows_in_tile = kTileElems / hidden_dim;

        // Per-thread: each thread owns its elements from the all-reduced tA in
        // register.  We'll also load residual_inp and accumulate.

        // Shared memory for per-row reduction of sum(x^2).
        // Each warp (64 threads) processes one row; we have 4 warps in the block.
        // Allocate enough for all rows in the tile.
        __shared__ float shared_sqsum[kRowsPerTile];

        // Iterate over rows within this tile that this thread participates in.
        // Each thread owns contiguous elements spanning possibly multiple rows.
        for(int row_idx = 0; row_idx < num_rows_in_tile; row_idx++)
        {
            int const row_global = tile_row_start + row_idx;
            int const row_elem_start = row_idx * hidden_dim;

            // Does this thread touch this row?
            int const my_first_elem = thread * kElemsPerThread;
            int const my_last_elem  = my_first_elem + kElemsPerThread;

            if(my_first_elem < (row_idx + 1) * (int)hidden_dim &&
               my_last_elem > row_idx * (int)hidden_dim)
            {
                // Thread's overlap with this row in the tile.
                int const in_row_start = max(my_first_elem, row_elem_start) - row_elem_start;
                int const in_row_end   = min(my_last_elem, row_elem_start + (int)hidden_dim) - row_elem_start;
                int const local_start  = max(my_first_elem, row_elem_start) - my_first_elem;
                int const local_end    = min(my_last_elem, row_elem_start + (int)hidden_dim) - my_first_elem;

                float sq_sum = 0.0f;
                // Add residual and write to residual_out, compute x^2 for
                // RMSNorm in the same pass.
                int atom_idx = local_start / kElemsPerAtom;
                int lane_in_atom = local_start % kElemsPerAtom;
                int elem_pos = local_start;

                while(elem_pos < local_end)
                {
                    int const atom_ofs = elem_pos / kElemsPerAtom;
                    int const lane     = elem_pos % kElemsPerAtom;

                    T* atom_ptr = reinterpret_cast<T*>(&tA[atom_ofs]);
                    T x_val = atom_ptr[lane];

                    // Load residual
                    uint32_t res_offset_byte = (uint32_t)(row_global) * hidden_dim * sizeof(T) +
                                               (uint32_t)(in_row_start + (elem_pos - local_start)) * sizeof(T);
                    BufferResource res_buffer(const_cast<T*>(residual_inp), N * sizeof(T));
                    // We can't use buffer_load for a single element easily.
                    // Instead load from global memory directly.
                    T residual_val;
                    {
                        T const* res_ptr = residual_inp + (uint32_t)(row_global) * hidden_dim +
                                           (uint32_t)(in_row_start + (elem_pos - local_start));
                        residual_val = *res_ptr;
                    }

                    T sum_val;
                    if constexpr(std::is_same<T, half>::value)
                    {
                        sum_val = __hadd(x_val, residual_val);
                    }
                    else
                    {
                        sum_val = __hadd(x_val, residual_val);
                    }

                    // Write to residual_out
                    T* res_out_ptr = residual_out + (uint32_t)(row_global) * hidden_dim +
                                     (uint32_t)(in_row_start + (elem_pos - local_start));
                    *res_out_ptr = sum_val;

                    float f_val = qr_to_float<T>(sum_val);
                    sq_sum += f_val * f_val;

                    elem_pos++;
                    if(elem_pos >= local_end) break;
                }

                // Warp reduction for this row's sum of squares.
                // All threads that touch this row are in the same warp (since
                // kElemsPerThread * blockDim.x == kTileElems, and hidden_dim <=
                // kTileElems, the threads covering one row form a contiguous
                // segment within the block).
                for(int mask = 16; mask > 0; mask >>= 1)
                {
                    sq_sum += __shfl_xor(sq_sum, mask);
                }

                // The first thread in the warp that covers this row writes to
                // shared memory.
                int const warp_lane = threadIdx.x % kWavefront;
                if(warp_lane == (in_row_start / kElemsPerThread) % kWavefront)
                {
                    shared_sqsum[row_idx] = sq_sum;
                }
            }
        }

        __syncthreads();

        // --------------------------------------------------------
        // Second pass: apply the normalization using the per-row sums from
        // shared memory.
        for(int row_idx = 0; row_idx < num_rows_in_tile; row_idx++)
        {
            int const row_global = tile_row_start + row_idx;
            float row_sqsum = shared_sqsum[row_idx];
            float denom = rsqrtf(row_sqsum / (float)hidden_dim + eps);

            int const my_first_elem = thread * kElemsPerThread;
            int const my_last_elem  = my_first_elem + kElemsPerThread;
            int const row_elem_start = row_idx * hidden_dim;

            if(my_first_elem < (row_idx + 1) * (int)hidden_dim &&
               my_last_elem > row_idx * (int)hidden_dim)
            {
                int const in_row_start = max(my_first_elem, row_elem_start) - row_elem_start;
                int const in_row_end   = min(my_last_elem, row_elem_start + (int)hidden_dim) - row_elem_start;
                int const local_start  = max(my_first_elem, row_elem_start) - my_first_elem;
                int const local_end    = min(my_last_elem, row_elem_start + (int)hidden_dim) - my_first_elem;

                int elem_pos = local_start;
                while(elem_pos < local_end)
                {
                    int const atom_ofs = elem_pos / kElemsPerAtom;
                    int const lane     = elem_pos % kElemsPerAtom;

                    T* atom_ptr = reinterpret_cast<T*>(&tA[atom_ofs]);
                    T x_val = atom_ptr[lane];

                    float f_val = qr_to_float<T>(x_val);
                    float normed = f_val * denom;

                    // Multiply by weight
                    T const* w_ptr = weight + (uint32_t)(in_row_start + (elem_pos - local_start));
                    float w_val = qr_to_float<T>(*w_ptr);
                    float result = normed * w_val;

                    // Write to output
                    T* out_ptr = output + (uint32_t)(row_global) * hidden_dim +
                                 (uint32_t)(in_row_start + (elem_pos - local_start));
                    *out_ptr = qr_from_float<T>(result);

                    elem_pos++;
                }
            }
        }
    }

