                    float f_val = qr_to_float<T>(sum_val);
                    sq_sum += f_val * f_val;

                    elem_pos++;
                    if(elem_pos >= local_end) break;
                }

                // Warp reduction for this row's sum of squares.
                // All threads that touch this row are in the same warp (since
                // kElemsPerThread * blockDim.x == kTileElems, and hidden_dim <=
                // kTileElems, the threads covering one row form a contiguous
                // segment within the block).
                for(int mask = 16; mask > 0; mask >>= 1)
                {
                    sq_sum += __shfl_xor(sq_sum, mask);
                }

                // The first thread in the warp that covers this row writes to
                // shared memory.
                int const warp_lane = threadIdx.x % kWavefront;
                if(warp_lane == (in_row_start / kElemsPerThread) % kWavefront)
                {
                    shared_sqsum[row_idx] = sq_sum;
                }
            }
        }

        __syncthreads();

        // --------------------------------------------------------
        // Second pass: apply the normalization using the per-row sums from
        // shared memory.
        for(int row_idx = 0; row_idx < num_rows_in_tile; row_idx++)
        {
            int const row_global = tile_row_start + row_idx;
            float row_sqsum = shared_sqsum[row_idx];
            float denom = rsqrtf(row_sqsum / (float)hidden_dim + eps);

            int const my_first_elem = thread * kElemsPerThread;
            int const my_last_elem  = my_first_elem + kElemsPerThread;
            int const row_elem_start = row_idx * hidden_dim;

            if(my_first_elem < (row_idx + 1) * (int)hidden_dim &&
               my_last_elem > row_idx * (int)hidden_dim)
            {
                int const in_row_start = max(my_first_elem, row_elem_start) - row_elem_start;
                int const in_row_end   = min(my_last_elem, row_elem_start + (int)hidden_dim) - row_elem_start;
                int const local_start  = max(my_first_elem, row_elem_start) - my_first_elem;
                int const local_end    = min(my_last_elem, row_elem_start + (int)hidden_dim) - my_first_elem;

                int elem_pos = local_start;
                while(elem_pos < local_end)
                {
                    int const atom_ofs = elem_pos / kElemsPerAtom;
                    int const lane     = elem_pos % kElemsPerAtom;

                    T* atom_ptr = reinterpret_cast<T*>(&tA[atom_ofs]);
                    T x_val = atom_ptr[lane];

                    float f_val = qr_to_float<T>(x_val);
                    float normed = f_val * denom;

                    // Multiply by weight
                    T const* w_ptr = weight + (uint32_t)(in_row_start + (elem_pos - local_start));
                    float w_val = qr_to_float<T>(*w_ptr);
                    float result = normed * w_val;

                    // Write to output
                    T* out_ptr = output + (uint32_t)(row_global) * hidden_dim +
                                 (uint32_t)(in_row_start + (elem_pos - local_start));
                    *out_ptr = qr_from_float<T>(result);

                    elem_pos++;
                }
            }
        }
    }

