// Number of elements per thread (8 atoms x 4 int32 lanes / atoms_per_int32)
    static constexpr int kElemsPerThread = kAtoms * (sizeof(int32x4_t) / sizeof(T));

    __device__ static void run(T const* __restrict__ input,
                               T const* __restrict__ residual_inp,
                               T* __restrict__ residual_out,
                               T* __restrict__ output,
                               T const* __restrict__ weight,
                               float eps,
                               uint32_t const N,
                               uint32_t const hidden_dim,
                               int const block,
                               int const rank,
                               uint8_t** __restrict__ buffer_list,
                               uint32_t const data_offset,
                               uint32_t flag_color,
                               int64_t data_size_per_phase)
    {
        // Topology
        int thread           = threadIdx.x + threadIdx.y * kWavefront;
        uint8_t* rank_buffer = buffer_list[rank];
        Codec codec(thread, rank);
        int block_id = blockIdx.x;
        uint8_t* buffer_ptr[kWorldSize];
        for(int i = 0; i < kWorldSize; ++i)
        {
            buffer_ptr[i] = buffer_list[i];
        }

        // --------------------------------------------------------
        // Read input into registers
        int32x4_t tA[kAtoms];

        BufferResource src_buffer(const_cast<T*>(input), N * sizeof(T));
        uint32_t src_offset = block * kTileSize + thread * sizeof(int32x4_t);

        for(int i = 0; i < kAtoms; i++)
        {
            tA[i] = buffer_load_dwordx4(src_buffer.descriptor, src_offset, 0, 0);
            src_offset += kAtomStride * sizeof(int32x4_t);
            if constexpr(cast_bf2half)
            {
                const nv_bfloat162* bf_buf = reinterpret_cast<const nv_bfloat162*>(&tA[i]);
                half2 half_buf[4];
#pragma unroll
                for(int j = 0; j < 4; ++j)
                {
                    float2 f    = __bfloat1622float2(bf_buf[j]);
                    half_buf[j] = __float22half2_rn(f);
                }
                tA[i] = *reinterpret_cast<const int32x4_t*>(half_buf);
            }
        }

        // --------------------------------------------------------
        // Phase-1A: Write segment data into the communication buffer of the target
        // rank responsible for this segment.
        uint32_t comm_data0_offset = data_offset + block_id * Codec::kTransmittedTileSize;
        uint32_t comm_data1_offset = data_size_per_phase + comm_data0_offset;

        uint32_t comm_flags0_offset = block_id * (kWorldSize * sizeof(uint32_t));
        uint32_t comm_flags1_offset = (data_offset / 2) + comm_flags0_offset;

        for(int r = 0; r < kWorldSize; r++)
        {
            int32x4_t* send_buffer = reinterpret_cast<int32x4_t*>(
                buffer_ptr[r] + comm_data0_offset + rank * Codec::kRankTransmittedTileSize);
            codec.send(send_buffer, &tA[r * Codec::kRankAtoms]);
        }

        __syncthreads();
        if(thread < kWorldSize)
        {
            int r              = thread;
            uint32_t* flag_ptr = reinterpret_cast<uint32_t*>(buffer_ptr[r] + comm_flags0_offset +
                                                              rank * sizeof(uint32_t));
            set_sync_flag(flag_ptr, flag_color);
        }

        // --------------------------------------------------------
        // Phase-1B: Reduce the segment data from the communication buffers.
        int32x4_t tR[Codec::kRankAtoms] = {};
        {
            int32x4_t* recv_buffer = reinterpret_cast<int32x4_t*>(rank_buffer + comm_data0_offset);
            uint32_t* flag_ptr     = reinterpret_cast<uint32_t*>(rank_buffer + comm_flags0_offset);

            for(int r = 0; r < kWorldSize; r++)
            {
                if(thread == 0)
                {
                    wait_sync_flag(&flag_ptr[r], flag_color);
                }
                __syncthreads();

                codec.recv(&recv_buffer, tA);

                for(int i = 0; i < Codec::kRankAtoms; i++)
                {
                    packed_assign_add<T>(&tR[i], &tA[i]);
                }
            }
        }

        // --------------------------------------------------------
        // Phase-2: Write the reduced segment to every other rank
        for(int r = 0; r < kWorldSize; r++)
        {
            int32x4_t* send_buffer = reinterpret_cast<int32x4_t*>(
                buffer_ptr[r] + comm_data1_offset + rank * Codec::kRankTransmittedTileSize);
            codec.send(send_buffer, tR);
        }

        __syncthreads();
        if(thread < kWorldSize)
        {
            int r              = thread;
            uint32_t* flag_ptr = reinterpret_cast<uint32_t*>(buffer_ptr[r] + comm_flags1_offset +
                                                              rank * sizeof(uint32_t));
            set_sync_flag(flag_ptr, flag_color);
        }

        // --------------------------------------------------------
        // Phase-2: Read the gather segments from the rank's communication buffer.
        {
            int32x4_t* recv_buffer = reinterpret_cast<int32x4_t*>(rank_buffer + comm_data1_offset);
            uint32_t* flag_ptr     = reinterpret_cast<uint32_t*>(rank_buffer + comm_flags1_offset);

            for(int r = 0; r < kWorldSize; r++)
            {
                if(thread == 0)
                {
                    wait_sync_flag(&flag_ptr[r], flag_color);
                }
                __syncthreads();

                codec.recv(&recv_buffer, &tA[r * Codec::kRankAtoms]);
            }
        }

        // --------------------------------------------------------
        // Fused add-residual + RMSNorm epilogue.
        //
        // The tile (kTileSize bytes) contains (kTileSize / (hidden_dim * sizeof(T)))
        // complete rows. Each thread owns kElemsPerThread contiguous elements.
        //
        // Strategy: for each row in the tile:
        //   1. Add residual element-by-element: x += residual_inp[i]
        //      (writing the sum to residual_out in the same pass)
        //   2. Accumulate sum-of-squares for the thread's portion of the row
        //   3. Reduce sum-of-squares across all threads covering this row
        //      (warp shuffle within the warp, then through shared memory across warps)
        //   4. Compute denom = rsqrt(mean + eps), then normalize and write output
        // --------------------------------------------------------

        int const tile_elems    = kTileSize / (int)sizeof(T);
        int const num_rows      = tile_elems / (int)hidden_dim;
        int const tile_row_base = ((int)block * kTileSize / (int)sizeof(T)) / (int)hidden_dim;

        // Shared memory: one float per row for the sqsum reduction.
        __shared__ float row_sqsum[8];

        // ---- Pass 1: residual add, write residual_out, accumulate x^2 ----
        for(int r = 0; r < num_rows; r++)
        {
            int const row_global  = tile_row_base + r;
            int const thread_elem = thread * kElemsPerThread;
            int const row_start   = r * (int)hidden_dim;
            int const row_end     = row_start + (int)hidden_dim;

            float my_sq = 0.0f;
            if(thread_elem < row_end && thread_elem + kElemsPerThread > row_start)
            {
                int const lo = max(thread_elem, row_start);
                int const hi = min(thread_elem + kElemsPerThread, row_end);

                for(int pos = lo; pos < hi; pos++)
                {
                    int const atom_ofs = (pos - row_start) / kElemsPerAtom;
                    int const lane     = (pos - row_start) % kElemsPerAtom;

                    // all-reduced value from tA
                    T const* atom_ptr = reinterpret_cast<T const*>(&tA[atom_ofs]);
                    T x_val = atom_ptr[lane];

                    // residual
                    uint32_t res_idx = (uint32_t)row_global * hidden_dim + (uint32_t)(pos - row_start);
                    T residual_val = residual_inp[res_idx];

                    // sum
                    T sum_val;
                    if constexpr(std::is_same<T, half>::value)
                    {
                        sum_val = __hadd(x_val, residual_val);
                    }
                    else
                    {
                        sum_val = __hadd(x_val, residual_val);
                    }

                    // Write residual_out
                    residual_out[res_idx] = sum_val;

                    // Accumulate x^2
                    float fv = qr_to_float<T>(sum_val);
                    my_sq += fv * fv;
                }
            }

            // Warp-level reduction (64 threads per warp).
            // Within a warp, all threads covering this row participate.
            // hidden_dim / kElemsPerThread threads cover a row.
            // There are 4 warps, each can handle one row since each row
            // spans roughly hidden_dim/32 threads.
            for(int mask = kWavefront / 2; mask > 0; mask >>= 1)
            {
                my_sq += __shfl_xor(my_sq, mask);
            }

            // Write to shared memory (lane 0 of each warp that has data for this row)
            int const warp_id = thread / kWavefront;
            if((thread % kWavefront) == 0 && warp_id < num_rows)
            {
                row_sqsum[warp_id] = my_sq;
            }

            // If this row spans multiple warps, we need to reduce across them.
            // hidden_dim / 32 elements per thread -> hidden_dim/32 threads per row.
            // With 256 threads, if hidden_dim/32 > 64 (i.e. hidden_dim > 2048 elements),
            // a single row spans >1 warp. Since hidden_dim*sizeof(T) divides kTileSize=32768,
            // hidden_dim <= 16384 for fp16, hidden_dim/32 <= 512. In practice for
            // hidden_dim=4096, that's 128 threads = 2 warps.
        }

        __syncthreads();

        // Handle the case where a row spans multiple warps: reduce across warps.
        for(int r = 0; r < num_rows; r++)
        {
            int threads_per_row = hidden_dim / kElemsPerThread;
            int warps_per_row = (threads_per_row + kWavefront - 1) / kWavefront;

            if(warps_per_row > 1)
            {
                // Reduce across warps: warp 0 accumulates from other warps.
                int const warp_id = thread / kWavefront;
                int const lane    = thread % kWavefront;
                int const warp_row_base = r * warps_per_row;

                if(warp_id >= warp_row_base && warp_id < warp_row_base + warps_per_row)
                {
                    int row_warp_idx = warp_id - warp_row_base;
                    if(lane == 0 && row_warp_idx > 0)
                    {
                        row_sqsum[r] += row_sqsum[warp_id];
                    }
                }
            }
        }

        __syncthreads();

        // ---- Pass 2: apply normalization ----
        for(int r = 0; r < num_rows; r++)
        {
            float denom = rsqrtf(row_sqsum[r] / (float)hidden_dim + eps);

            int const row_global  = tile_row_base + r;
            int const thread_elem = thread * kElemsPerThread;
            int const row_start   = r * (int)hidden_dim;
            int const row_end     = row_start + (int)hidden_dim;

            if(thread_elem < row_end && thread_elem + kElemsPerThread > row_start)
            {
                int const lo = max(thread_elem, row_start);
                int const hi = min(thread_elem + kElemsPerThread, row_end);

                for(int pos = lo; pos < hi; pos++)
                {
                    int const in_row = pos - row_start;
                    int const atom_ofs = in_row / kElemsPerAtom;
                    int const lane     = in_row % kElemsPerAtom;

                    T const* atom_ptr = reinterpret_cast<T const*>(&tA[atom_ofs]);
                    T x_val = atom_ptr[lane];

                    // Load residual value from residual_out (already written in pass 1)
                    // Actually we need the sum, not just the original all-reduced value.
                    // But we already wrote residual_out in pass 1, so read it back.
                    uint32_t out_idx = (uint32_t)row_global * hidden_dim + (uint32_t)in_row;

                    // For RMSNorm: x * rsqrt(mean(x^2) + eps) * weight
                    // x is the sum (all-reduced + residual), which is in residual_out.
                    // But reading residual_out back from HBM defeats the purpose of fusion.
                    // We need to recompute from tA + residual_inp in register.
                    // But we already updated tA? No, tA still holds the all-reduced value.
                    // We need the sum = tA_value + residual. We have both in registers
                    // (the sum was computed but stored only to HBM). Recompute from tA + residual_inp.

                    T residual_val = residual_inp[out_idx];

                    T sum_val;
                    if constexpr(std::is_same<T, half>::value)
                    {
                        sum_val = __hadd(x_val, residual_val);
                    }
                    else
                    {
                        sum_val = __hadd(x_val, residual_val);
                    }

                    float fv = qr_to_float<T>(sum_val);
                    float normed = fv * denom;

                    T w_val = weight[in_row];
                    float wf = qr_to_float<T>(w_val);
                    float result = normed * wf;

                    output[out_idx] = qr_from_float<T>(result);
                }
            }
        }
    }

