arguments.newString:
// --------------------------------------------------------
        // Fused add-residual + RMSNorm epilogue.
        //
        // The tile (kTileSize bytes) packs several complete rows of
        // hidden_dim elements each.  Each thread owns a contiguous chunk
        // of kElemsPerThread elements within the tile.
        //
        // We do a two-pass approach over each row in the tile:
        //   Pass 1 — load residual, write sum to residual_out, accumulate
        //            x^2 for this thread's portion of the row, then reduce
        //            across all threads covering the row via shared memory.
        //   Pass 2 — broadcast the row's denom, recompute the sum from
        //            tA + residual_inp (still in registers / cached), apply
        //            weight, and write the normalized output.
        //
        // Recomputing the sum avoids storing into + reading back from an
        // intermediate HBM buffer and is the whole point of the fusion.
        // --------------------------------------------------------

        int const tile_elems    = kTileSize / (int)sizeof(T);
        int const num_rows      = tile_elems / (int)hidden_dim;
        int const tile_row_base = ((int)block * kTileSize / (int)sizeof(T)) / (int)hidden_dim;

        // Number of threads that cover one complete row.
        int const threads_per_row = ((int)hidden_dim + kElemsPerThread - 1) / kElemsPerThread;

        // Shared memory for row-local sqsum reduction.
        __shared__ float sh_sqsum[8];

        // ---- Pass 1: add residual, write residual_out, accumulate x^2 ----
        for(int r = 0; r < num_rows; r++)
        {
            int const row_global  = tile_row_base + r;
            int const thread_elem = thread * kElemsPerThread;
            int const row_start   = r * (int)hidden_dim;
            int const row_end     = row_start + (int)hidden_dim;

            float my_sq = 0.0f;
            if(thread_elem < row_end && thread_elem + kElemsPerThread > row_start)
            {
                int const lo = max(thread_elem, row_start);
                int const hi = min(thread_elem + kElemsPerThread, row_end);

                for(int pos = lo; pos < hi; pos++)
                {
                    int const in_row   = pos - row_start;
                    int const atom_ofs = in_row / kElemsPerAtom;
