// --------------------------------------------------------
        // Fused add-residual + RMSNorm epilogue.
        //
        // The tile (kTileSize bytes = 16384 elems) is row-major: row i
        // occupies elements [i*hidden_dim, (i+1)*hidden_dim).  Each thread
        // owns 8 atoms × 8 T-elements per atom = 64 elements, strided
        // across the tile: atom j (j=0..7) at byte offset
        // j*4096 + thread*16 gives 8 contiguous T elements.
        //
        // For hidden_dim such that hidden_dim*sizeof(T) | kTileSize, the
        // rows partition the tile perfectly.
        //
        // Pass 1 — for each row in the tile: add residual, write sum to
        //           residual_out, accumulate x^2.  Reduce via tree in
        //           shared memory.
        // Pass 2 — compute denom, apply normalization and weight, write
        //           output (recomputing sum from tA + residual_inp).
        // --------------------------------------------------------

        int const tile_elems    = kTileSize / (int)sizeof(T);
        int const num_rows      = tile_elems / (int)hidden_dim;
        int const tile_row_base = ((int)block * kTileSize / (int)sizeof(T)) / (int)hidden_dim;

        __shared__ float sh_sqsum[256];
        if(thread < tile_elems / (int)kElemsPerThread)
        {
            sh_sqsum[thread] = 0.0f;
        }
        __syncthreads();

        // ---- Pass 1: add residual, write residual_out, accumulate x^2 ----
        // Determine which atom chunks (each 2048 elems) this thread touches.
        for(int r = 0; r < num_rows; r++)
        {
            int const row_global  = tile_row_base + r;
            int const row_start   = r * (int)hidden_dim;
            int const row_end     = row_start + (int)hidden_dim;

            float my_sq = 0.0f;

            // For each of the 8 atoms, check if its element range overlaps the row.
            // Atom j covers elements [j*2048, j*2048+2048) within the tile.
            for(int j = 0; j < kAtoms; j++)
            {
                int const atom_elem_start = j * kAtomStride * ((int)sizeof(int32x4_t) / (int)sizeof(T));
                // kAtomStride=256, sizeof(int32x4_t)=16, sizeof(T)=2 →
                // stride = 256 * 8 = 2048 elements per atom.
                // Actually: kAtomStride * sizeof(int32x4_t) = 256*16 = 4096 bytes = 2048 elements.
                int const atom_elem_end = atom_elem_start + (int)kElemsPerAtom;

                if(atom_elem_start < row_end && atom_elem_end > row_start)
                {
                    // This thread contributes element thread*8 within this atom.
                    int const thread_elem_in_atom = thread * (int)kElemsPerAtom;
                    // The atom's elements in global tile coords:
                    int const tile_elem = atom_elem_start + thread_elem_in_atom;

                    if(tile_elem >= row_start && tile_elem < row_end)
                    {
                        // All 8 elements in this atom fragment are within the row.
                        int const in_row = tile_elem - row_start;

                        // This thread owns kElemsPerAtom=8 elements from this atom.
                        for(int l = 0; l < (int)kElemsPerAtom; l++)
                        {
                            float x_val;
                            if constexpr(cast_bf2half)
                            {
                                half const* hp = reinterpret_cast<half const*>(&tA[j]);
                                x_val = __half2float(hp[thread * (int)kElemsPerAtom + l]);
                            }
                            else
                            {
                                T const* tp = reinterpret_cast<T const*>(&tA[j]);
                                x_val = qr_to_float<T>(tp[thread * (int)kElemsPerAtom + l]);
                            }

                            uint32_t const gidx = (uint32_t)row_global * hidden_dim + (uint32_t)(in_row + l);
                            float rval = qr_to_float<T>(residual_inp[gidx]);
                            float sum_val = x_val + rval;
                            residual_out[gidx] = qr_from_float<T>(sum_val);
                            my_sq += sum_val * sum_val;
                        }
                    }
                }
            }

            sh_sqsum[thread] = my_sq;
            __syncthreads();

            // Tree reduction across all threads in the block.
            for(int s = kBlockSize / 2; s > 0; s >>= 1)
            {
                if(thread < s)
                {
                    sh_sqsum[thread] += sh_sqsum[thread + s];
                }
                __syncthreads();
            }

            // sh_sqsum[0] has the total sum for this row.
            // Store it in a safe spot for Pass 2.
            if(thread == 0)
            {
                sh_sqsum[16 + r] = sh_sqsum[0];
            }
            __syncthreads();
        }

        // ---- Pass 2: apply normalization ----
        for(int r = 0; r < num_rows; r++)
